import React, { useRef, useEffect, useState } from 'react';
import { usePlayer } from '../context/PlayerContext';
import { FaPlay, FaPause, FaStepForward, FaStepBackward, FaRandom, FaRedo, FaVolumeUp, FaHeart, FaUserPlus, FaList } from 'react-icons/fa';

const Player = () => {
  const { currentSong, isPlaying, setIsPlaying, togglePlay } = usePlayer();
  const audioRef = useRef(null);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);

  // Xử lý Play/Pause khi đổi bài
  useEffect(() => {
    if (currentSong && audioRef.current) {
      if (isPlaying) {
        audioRef.current.play();
      } else {
        audioRef.current.pause();
      }
    }
  }, [currentSong, isPlaying]);

  // Cập nhật thời gian thực
  const handleTimeUpdate = () => {
    if(audioRef.current) {
        setCurrentTime(audioRef.current.currentTime);
        setDuration(audioRef.current.duration || 0);
    }
  };

  // Tua nhạc
  const handleSeek = (e) => {
    const seekTime = (e.target.value / 100) * duration;
    audioRef.current.currentTime = seekTime;
    setCurrentTime(seekTime);
  };

  // Format giây thành phút:giây (ví dụ: 3:57)
  const formatTime = (time) => {
    if (!time) return "0:00";
    const min = Math.floor(time / 60);
    const sec = Math.floor(time % 60);
    return `${min}:${sec < 10 ? '0' + sec : sec}`;
  };

  if (!currentSong) return null;

  return (
    // Tăng chiều cao từ h-[48px] lên h-[60px]
    <div className="fixed bottom-0 left-0 right-0 bg-[#111] text-white h-[60px] border-t border-[#333] flex items-center px-2 z-50 font-sans select-none">
      {/* Audio Element Ẩn */}
      <audio 
        ref={audioRef} 
        src={currentSong.audioUrl} 
        onEnded={() => setIsPlaying(false)}
        onTimeUpdate={handleTimeUpdate}
        onLoadedMetadata={handleTimeUpdate}
      />

      {/* 1. Nhóm Điều Khiển (Trái) */}
      <div className="flex items-center gap-6 px-6 w-[240px] justify-start">
        <button className="text-white hover:text-orange-500 transition"><FaStepBackward size={18} /></button>
        <button 
          onClick={togglePlay}
          className="text-white hover:text-orange-500 transition"
        >
          {/* Tăng kích thước nút Play/Pause */}
          {isPlaying ? <FaPause size={28} /> : <FaPlay size={28} />}
        </button>
        <button className="text-white hover:text-orange-500 transition"><FaStepForward size={18} /></button>
        <button className="text-gray-400 hover:text-white hidden sm:block"><FaRandom size={16} /></button>
        <button className="text-gray-400 hover:text-white hidden sm:block"><FaRedo size={16} /></button>
      </div>

      {/* 2. Thanh Tiến Trình (Giữa) */}
      <div className="flex-1 flex items-center gap-4 px-4">
        {/* Thời gian hiện tại (Màu cam) */}
        <span className="text-[#f50] text-xs font-medium w-10 text-right">{formatTime(currentTime)}</span>
        
        {/* Thanh trượt */}
        <div className="relative flex-1 h-[2px] bg-[#333] group cursor-pointer">
           {/* Input ẩn để kéo tua */}
           <input 
              type="range" 
              min="0" 
              max="100" 
              value={duration ? (currentTime / duration) * 100 : 0}
              onChange={handleSeek}
              className="absolute w-full h-[12px] -top-[5px] opacity-0 cursor-pointer z-20"
           />
           {/* Nền thanh */}
           <div className="absolute top-0 left-0 w-full h-full bg-[#333]"></div>
           {/* Phần đã chạy (Màu cam) */}
           <div 
              className="absolute top-0 left-0 h-full bg-[#f50]" 
              style={{ width: `${duration ? (currentTime / duration) * 100 : 0}%` }}
           ></div>
           {/* Cục tròn (Handle) - Chỉ hiện khi hover */}
           <div 
              className="absolute top-1/2 -translate-y-1/2 w-3 h-3 bg-[#f50] rounded-full opacity-0 group-hover:opacity-100 transition z-10 pointer-events-none"
              style={{ left: `${duration ? (currentTime / duration) * 100 : 0}%` }}
           ></div>
        </div>

        {/* Tổng thời gian */}
        <span className="text-gray-400 text-xs font-medium w-10">{formatTime(duration)}</span>
        
        {/* Icon Volume */}
        <button className="text-white hover:text-white ml-2"><FaVolumeUp size={18} /></button>
      </div>

      {/* 3. Thông Tin Bài Hát (Phải) */}
      <div className="flex items-center gap-4 px-6 w-[360px] justify-end border-l border-[#333] h-full">
        <div className="flex items-center gap-3 flex-1 min-w-0">
            {/* Tăng kích thước ảnh bìa lên 40px (w-10 h-10) */}
            <img src={currentSong.coverImage || 'https://via.placeholder.com/40'} alt="cover" className="w-10 h-10 object-cover shadow-sm" />
            <div className="flex flex-col justify-center overflow-hidden">
                <span className="text-gray-400 text-[11px] truncate hover:underline cursor-pointer">{currentSong.artist}</span>
                <span className="text-gray-200 text-xs truncate font-medium hover:text-white cursor-pointer">{currentSong.title}</span>
            </div>
        </div>

        <div className="flex items-center gap-5 text-white">
            <button className="hover:text-orange-500 transition"><FaHeart size={16} /></button>
            <button className="hover:text-orange-500 transition"><FaUserPlus size={18} /></button>
            <button className="hover:text-orange-500 transition"><FaList size={18} /></button>
        </div>
      </div>
    </div>
  );
};

export default Player;
